from flask import Flask, request, jsonifyfrom telethon import TelegramClientimport asyncioimport base64import osfrom tg_messages import get_chat_previewfrom tg_search import search_chatsfrom tg_send import send_messagesapp = Flask(__name__)API_ID = 30101072API_HASH = 'e0f3d73a25cc1c3084fb3341fb526955'PHONE = '+79204962556'DEVICE_PARAMS = {    "device_model": "Samsung S23 Ultra",    "system_version": "Android 13",    "app_version": "9.6.1",    "lang_code": "en",    "system_lang_code": "en-US"}client = TelegramClient(    'session_web',    API_ID,    API_HASH,    device_model=DEVICE_PARAMS["device_model"],    system_version=DEVICE_PARAMS["system_version"],    app_version=DEVICE_PARAMS["app_version"],    lang_code=DEVICE_PARAMS["lang_code"],    system_lang_code=DEVICE_PARAMS["system_lang_code"])loop = asyncio.new_event_loop()asyncio.set_event_loop(loop)def run_async(coro):    return loop.run_until_complete(coro)async def auth():    await client.start(PHONE)    print("✅ Telegram готов")run_async(auth())def get_avatar(entity):    """Безопасное получение аватара"""    try:        photo = run_async(client.download_profile_photo(entity))        if photo and os.path.exists(photo):            with open(photo, 'rb') as f:                avatar = base64.b64encode(f.read()).decode('utf-8')            os.remove(photo)            return avatar    except Exception as e:        print(f"Avatar error: {e}")    return None@app.route('/api/chats/all')def get_all_chats():    async def fetch():        result = []        async for d in client.iter_dialogs():            result.append({                'id': d.id,                'name': d.name,                'avatar': get_avatar(d.entity)            })            # Периодический вывод прогресса            if len(result) % 100 == 0:                print(f"Загружено {len(result)} чатов...")        return result    try:        data = run_async(fetch())        print(f"Всего загружено чатов: {len(data)}")        return jsonify(data)    except Exception as e:        print(f"Ошибка /api/chats/all: {e}")        return jsonify([]), 500@app.route('/api/search', methods=['POST'])def search():    try:        data = request.json        print(f"🔵 Получены данные от Java: {data}")        # Параметры соответствуют Java SearchParams        params = {            'term': data.get('term', 'Java'),            'maxFoundCount': data.get('maxFoundCount', 10),            'minDiffDaysCount': data.get('minDiffDaysCount', 7),            'excludeBotFlag': data.get('excludeBotFlag', True),            'excludeGroupFlag': data.get('excludeGroupFlag', True),            'excludeStatusFlag': data.get('excludeStatusFlag', True)        }        print(f"🔵 Параметры поиска: {params}")        found_chats = run_async(search_chats(client, params))        # Добавляем аватары к найденным чатам        for chat in found_chats:            async def get_avatar_for_chat():                try:                    entity = await client.get_entity(chat['id'])                    return get_avatar(entity)                except:                    return None            chat['avatar'] = run_async(get_avatar_for_chat())        return jsonify(found_chats)    except Exception as e:        print(f"🔴 Ошибка в search: {e}")        return jsonify([]), 500@app.route('/api/chat-preview/<chat_id>')def chat_preview(chat_id):    try:        chat_id = int(chat_id)    except ValueError:        return jsonify({'error': 'Invalid chat_id'}), 400    # Получаем параметр limit из запроса (если 0, то все сообщения)    limit = request.args.get('limit', default=None, type=int)    if limit == 0:        limit = None    try:        print(f"🔵 limit из запроса: {limit}, после преобразования: {limit if limit != 0 else None}")        result = run_async(get_chat_preview(client, chat_id, limit))        return jsonify(result)    except Exception as e:        print(f"Ошибка preview: {e}")        return jsonify({'messages': []}), 500@app.route('/api/send_bulk_messages', methods=['POST'])def send_bulk_messages():    data = request.json    chat_ids = data.get('chat_ids', [])    message_text = data.get('message_text', '')    delay = data.get('delay_seconds', 2)    only_new_chats = data.get('only_new_chats', False)  # Новый параметр    if not chat_ids:        return jsonify({'error': 'Нет чатов'}), 400    if not message_text:        return jsonify({'error': 'Нет текста'}), 400    try:        results = run_async(send_messages(client, chat_ids, message_text, delay, only_new_chats))        success_count = len([r for r in results if r['status'] == 'success'])        skipped_count = len([r for r in results if r['status'] == 'skipped'])        error_count = len([r for r in results if r['status'] == 'error'])        return jsonify({            'total': len(chat_ids),            'success': success_count,            'skipped': skipped_count,            'error': error_count,            'results': results        })    except Exception as e:        return jsonify({'error': str(e)}), 500@app.route('/api/export/<int:chat_id>')def export_chat(chat_id):    async def export():        chat_name = str(chat_id)        async for d in client.iter_dialogs():            if d.id == chat_id:                chat_name = d.name                break        messages = []        async for m in client.iter_messages(chat_id, limit=5000):            messages.append({'id': m.id, 'date': str(m.date), 'text': m.text[:500] if m.text else None})        os.makedirs('exports', exist_ok=True)        filename = f'exports/{chat_name.replace("/", "_").replace(" ", "_")}.json'        with open(filename, 'w', encoding='utf-8') as f:            import json            json.dump({                'chat_id': chat_id,                'chat_name': chat_name,                'total_messages': len(messages),                'messages': messages            }, f, ensure_ascii=False, indent=2)        return {'filename': filename, 'total': len(messages)}    try:        result = run_async(export())        return jsonify(result)    except Exception as e:        return jsonify({'error': str(e)}), 500if __name__ == '__main__':    print("🚀 Сервер на http://localhost:8081")    app.run(debug=False, port=8081, threaded=False)